%dw 2.0 output application/json --- { // Splunk HEC envelope "time": now() as Number, "host": "mule-inventory-sync", "source": p('splunk.hec.source'), "sourcetype": "mule:inventory_sync", "index": p('splunk.hec.index'),
// Event body - searchable fields in Splunk "event": { "severity": "ERROR", "alert_type": "FILE_NOT_FOUND", "environment": p('app.env'), "process_date": vars.processDate, "expected_file": vars.expectedFileName, "sftp_source": p('sftp.source.host') ++ p('sftp.source.workingDir'), "correlation_id": correlationId, "timestamp": now() as String, "message": "Inventory CSV file not found in source SFTP location", "action_required": "Verify Oracle WMS batch job completed. File: " ++ vars.expectedFileName,
// Dashboard fields "job_status": "FAILED", "records_total": 0, "records_valid": 0, "records_invalid": 0, "files_generated": 0 } }

%dw 2.0 output application/json --- { "time": now() as Number, "host": "mule-inventory-sync", "source": p('splunk.hec.source'), "sourcetype": "mule:inventory_sync", "index": p('splunk.hec.index'),
"event": { "severity": "WARN", "alert_type": "INVALID_RECORDS", "environment": p('app.env'), "process_date": vars.processDate, "source_file": vars.expectedFileName, "correlation_id": correlationId, "timestamp": now() as String, "message": "Invalid records detected and excluded from processing",
// Dashboard fields - these drive Splunk charts "job_status": "COMPLETED_WITH_WARNINGS", "records_total": result.totalRecords, "records_valid": result.successfulRecords, "records_invalid": result.failedRecords, "success_rate": ((result.successfulRecords / result.totalRecords) * 100) as Number {format: "#.##"},
// Validation breakdown "validation_rules": { "mandatory_fields": "All fields required: SKU, StoreId, Type, Quantity, Timestamp", "quantity_rule": "Must be whole number (integer)", "type_rule": "Must be Standard or Backorder" } } }

%dw 2.0 output application/json --- { "time": now() as Number, "host": "mule-inventory-sync", "source": p('splunk.hec.source'), "sourcetype": "mule:inventory_sync", "index": p('splunk.hec.index'),
"event": { "severity": "CRITICAL", "alert_type": "SYSTEM_ERROR", "environment": p('app.env'), "process_date": vars.processDate default (now() as Date {format:"dd-MM-yyyy"} as String), "correlation_id": correlationId, "timestamp": now() as String, "message": error.description default "Unknown system error",
// Error details - searchable in Splunk "error_type": (error.errorType.namespace default "UNKNOWN") ++ ":" ++ (error.errorType.identifier default "UNKNOWN"), "error_detail": error.detailedDescription default "Not available",
// Dashboard fields "job_status": "FAILED", "records_total": 0, "records_valid": 0, "records_invalid": 0, "files_generated": 0 } }

%dw 2.0 output application/json --- { "time": now() as Number, "host": "mule-inventory-sync", "source": p('splunk.hec.source'), "sourcetype": "mule:inventory_sync", "index": p('splunk.hec.index'),
"event": { "severity": "INFO", "alert_type": "JOB_SUCCESS", "environment": p('app.env'), "process_date": vars.processDate, "source_file": vars.expectedFileName, "correlation_id": correlationId, "timestamp": now() as String, "message": "Inventory sync job completed successfully",
// Dashboard fields - drive your Splunk charts "job_status": "SUCCESS", "records_total": result.totalRecords, "records_valid": result.successfulRecords, "records_invalid": result.failedRecords, "files_generated": vars.storeFilesGenerated default 0, "success_rate": 100,
// Performance metrics "sftp_source": p('sftp.source.host') ++ p('sftp.source.workingDir'), "sftp_target": p('sftp.target.host') ++ p('sftp.target.workingDir') } }
